import "./App.css";

import Sidebar from "./components/Sidebar";
import ChatBox from "./components/ChatBox";

function App() {

  return (

    <div className="app">

      <Sidebar />

      <div className="main">

        <div className="header">

          <h1>India AI Travel Planner</h1>

          <p>
            Budget-Oriented AI Tourism Assistant
          </p>

        </div>

        <ChatBox />

      </div>

    </div>
  );
}

export default App;
